    $checker = new CasinoAvailabilityChecker();
    try {
        $available = $checker->isAvailable('example-casino', 'US');
        echo $available ? 'Available' : 'Not Available';
    } catch (Exception $e) {
        echo 'Error: ' . $e->getMessage();
    }
}
